 22→// Defines kinds of Sanitizer
 23→// The order in enum class should be same as one in flat buffer schema
 24→enum class SanitizerKind {
 25→  kNone = 0,
 26→  kAddress,
 27→  kThread,
 28→};
 29→
 30→// The LLVMTarget contains all of the information to perform code generation
 31→// and linking for an ExecutableVariant. It should not contain any
 32→// environmental configuration like linker paths, diagnostic aids, etc.
 33→struct LLVMTarget {
 34→  static constexpr const char *DEFAULT_DATA_LAYOUT = "";
 35→  static constexpr int64_t DEFAULT_VECTOR_WIDTH_IN_BYTES = 0;
 36→  static constexpr bool DEFAULT_LINK_EMBEDDED = true;
 37→  static constexpr bool DEFAULT_DEBUG_SYMBOLS = true;
 38→  static constexpr SanitizerKind DEFAULT_SANITIZER_KIND = SanitizerKind::kNone;
 39→  static constexpr bool DEFAULT_LINK_STATIC = false;
 40→  static constexpr bool DEFAULT_LOOP_INTERLEAVING = false;
 41→  static constexpr bool DEFAULT_LOOP_VECTORIZATION = false;
 42→  static constexpr bool DEFAULT_LOOP_UNROLLING = false;
 43→  static constexpr bool DEFAULT_SLP_VECTORIZATION = false;
 44→  static constexpr llvm::FloatABI::ABIType DEFAULT_FLOAT_ABI =
 45→      llvm::FloatABI::ABIType::Hard;
 46→  static constexpr const char *DEFAULT_ENABLE_UKERNELS = "default";
 47→  static constexpr bool DEFAULT_LINK_UKERNEL_BITCODE = true;
 48→
 49→  // Default initialize all fields.
 50→  LLVMTarget();
 51→
 52→  void copy(const LLVMTarget &other) {
 53→    triple = other.triple;
 54→    cpu = other.cpu;
 55→    cpuFeatures = other.cpuFeatures;
 56→    dataLayout = other.dataLayout;
 57→    vectorWidthInBytes = other.vectorWidthInBytes;
 58→    linkEmbedded = other.linkEmbedded;
 59→    ukernels = other.ukernels;
 60→    linkUkernelBitcode = other.linkUkernelBitcode;
 61→  }
 62→
 63→  void print(llvm::raw_ostream &os) const;
 64→
 65→  // Stores the target to the given DictionaryAttr in a way that can be
 66→  // later loaded from loadFromConfigAttr().
 67→  void storeToConfigAttrs(MLIRContext *context,
 68→                          SmallVector<NamedAttribute> &config) const;
 69→
 70→  static std::optional<LLVMTarget>
 71→  create(std::string_view triple, std::string_view cpu,
 72→         std::string_view cpuFeatures, bool requestLinkEmbedded,
 73→         ResolveCPUAndCPUFeaturesStatus &status);
 74→
 75→  static std::optional<LLVMTarget> createForHost();
 76→
 77→  // Loads from a DictionaryAttr. On failure returns none and emits.
 78→  static std::optional<LLVMTarget>
 79→  loadFromConfigAttr(Location loc, DictionaryAttr config,
 80→                     const LLVMTarget &defaultTarget);
 81→
 82→  // Key fields about the machine can only be set via constructor.
 83→  const std::string &getTriple() const { return triple; }
 84→  const std::string &getCpu() const { return cpu; }
 85→  const std::string &getCpuFeatures() const { return cpuFeatures; }
 86→
 87→  // Overrides the data layout of the target.
 88→  std::string dataLayout = DEFAULT_DATA_LAYOUT;
 89→  // Overrides the vector width (in bytes) of the target.
 90→  int64_t vectorWidthInBytes = DEFAULT_VECTOR_WIDTH_IN_BYTES;
 91→
 92→  llvm::PipelineTuningOptions pipelineTuningOptions;
 93→  // Optimization level to be used by the LLVM optimizer (middle-end).
 94→  llvm::OptimizationLevel optimizerOptLevel;
 95→  // Optimization level to be used by the LLVM code generator (back-end).
 96→  llvm::CodeGenOptLevel codeGenOptLevel;
 97→  llvm::TargetOptions llvmTargetOptions;
 98→
 99→  bool getLinkEmbedded() const { return linkEmbedded; }
100→
101→  // Include debug information in output files (PDB, DWARF, etc).
102→  // Though this can be set independently from the optLevel (so -O3 with debug
103→  // information is valid) it may significantly change the output program
104→  // contents and benchmarking of binary sizes and to some extent execution
105→  // time should be avoided with symbols present.
106→  bool debugSymbols = DEFAULT_DEBUG_SYMBOLS;
107→
108→  // Sanitizer Kind for CPU Kernels
109→  SanitizerKind sanitizerKind = DEFAULT_SANITIZER_KIND;
110→
111→  // Build for IREE static library loading using this output path for
112→  // a "{staticLibraryOutput}.o" object file and "{staticLibraryOutput}.h"
113→  // header file.
114→  //
115→  // This option is incompatible with the linkEmbedded option.
116→  std::string staticLibraryOutput;
117→
118→  // Link any required runtime libraries into the produced binaries statically.
119→  // This increases resulting binary size but enables the binaries to be used on
120→  // any machine without requiring matching system libraries to be installed.
121→  bool linkStatic = DEFAULT_LINK_STATIC;
122→
123→  // Enables ukernels in the generated executables. May be `default`, `none`,
124→  // `all`, or a comma-separated list of specific unprefixed ukernels to
125→  // enable, e.g. `mmt4d`.
126→  std::string ukernels = DEFAULT_ENABLE_UKERNELS;
127→
128→  // Link built-in ukernel bitcode libraries into generated executables.
129→  bool linkUkernelBitcode = DEFAULT_LINK_UKERNEL_BITCODE;
130→
131→private:
132→  void populateDefaultsFromTargetMachine();
133→
134→  std::string triple;
135→  std::string cpu;
136→  std::string cpuFeatures;
137→
138→  // Build for the IREE embedded platform-agnostic ELF loader.
139→  // Note: this is ignored for target machines that do not support the ELF
140→  // loader, such as WebAssembly.
141→  bool linkEmbedded = DEFAULT_LINK_EMBEDDED;
142→
143→  friend struct LLVMTargetOptions;
144→  friend struct LLVMCPUTargetCLOptions;
145→};
146→
147→struct LLVMTargetOptions {
148→  // Default target machine configuration.
149→  LLVMTarget target;
150→
151→  // Tool to use for native platform linking (like ld on Unix or link.exe on
152→  // Windows). Acts as a prefix to the command line and can contain additional
153→  // arguments.
154→  std::string systemLinkerPath;
155→
156→  // Tool to use for linking embedded ELFs. Must be lld.
157→  std::string embeddedLinkerPath;
158→
159→  // Tool to use for linking WebAssembly modules. Must be wasm-ld or lld.
160→  std::string wasmLinkerPath;
161→
162→  // True to keep linker artifacts for debugging.
163→  bool keepLinkerArtifacts = false;
164→
165→  // Regex filter for LLVM optimization remarks (e.g., "regalloc").
166→  std::string remarksFilter;
167→};
168→
169→// Creates target machine form target options.
170→std::unique_ptr<llvm::TargetMachine>
171→createTargetMachine(const LLVMTarget &target);
172→
173→// Raw commandline options for LLVMCPUTarget.
174→// Parse into LLVMTargetOptions using getTargetOptions().
175→struct LLVMCPUTargetCLOptions {
176→  // Target invariant flags.
177→  std::string systemLinkerPath;
178→  std::string embeddedLinkerPath;
179→  std::string wasmLinkerPath;
180→  bool keepLinkerArtifacts = false;
181→
182→  // Default device options.
183→  std::string targetTriple;
184→  std::string targetCPU;
185→  std::string loggingUnspecifiedTargetCPU;
186→  std::string targetCPUFeatures;
187→  bool linkEmbedded = LLVMTarget::DEFAULT_LINK_EMBEDDED;
188→  bool linkStatic = LLVMTarget::DEFAULT_LINK_STATIC;
189→  std::string staticLibraryOutputPath;
190→  bool debugSymbols = LLVMTarget::DEFAULT_DEBUG_SYMBOLS;
191→  bool llvmLoopInterleaving = LLVMTarget::DEFAULT_LOOP_INTERLEAVING;
192→  bool llvmLoopVectorization = LLVMTarget::DEFAULT_LOOP_VECTORIZATION;
193→  bool llvmLoopUnrolling = LLVMTarget::DEFAULT_LOOP_UNROLLING;
194→  bool llvmSLPVectorization = LLVMTarget::DEFAULT_SLP_VECTORIZATION;
195→  SanitizerKind sanitizerKind = LLVMTarget::DEFAULT_SANITIZER_KIND;
196→  std::string targetABI;
197→  llvm::FloatABI::ABIType targetFloatABI = LLVMTarget::DEFAULT_FLOAT_ABI;
198→  std::string targetDataLayout = LLVMTarget::DEFAULT_DATA_LAYOUT;
199→  unsigned targetVectorWidthInBytes = LLVMTarget::DEFAULT_VECTOR_WIDTH_IN_BYTES;
200→  std::string enableUkernels = LLVMTarget::DEFAULT_ENABLE_UKERNELS;
201→  bool linkUKernelBitcode = LLVMTarget::DEFAULT_LINK_UKERNEL_BITCODE;
202→  std::string remarksFilter;
203→  bool listTargets; // Ignored - used with llvm::cl::ValueDisallowed.
204→
205→  void bindOptions(OptionsBinder &binder);
206→  LLVMTargetOptions getTargetOptions();
207→};
