 26→LLVMTarget::LLVMTarget() {
 27→  // LLVM loop optimization options.
 28→  pipelineTuningOptions.LoopInterleaving = DEFAULT_LOOP_INTERLEAVING;
 29→  pipelineTuningOptions.LoopVectorization = DEFAULT_LOOP_VECTORIZATION;
 30→  pipelineTuningOptions.LoopUnrolling = DEFAULT_LOOP_UNROLLING;
 31→
 32→  // LLVM SLP Auto vectorizer.
 33→  pipelineTuningOptions.SLPVectorization = DEFAULT_SLP_VECTORIZATION;
 34→
 35→  // LLVM optimization levels.
 36→  // TODO(benvanik): add an option for this.
 37→  optimizerOptLevel = llvm::OptimizationLevel::O2;
 38→  codeGenOptLevel = llvm::CodeGenOptLevel::Aggressive;
 39→  llvmTargetOptions.FloatABIType = DEFAULT_FLOAT_ABI;
 40→
 41→  // Force `-ffunction-sections` so we can strip unused code.
 42→  llvmTargetOptions.FunctionSections = true;
 43→  llvmTargetOptions.DataSections = true;
 44→  llvmTargetOptions.UniqueSectionNames = true;
 45→}
 46→
 47→std::optional<LLVMTarget>
 48→LLVMTarget::create(std::string_view triple, std::string_view cpu,
 49→                   std::string_view cpuFeatures, bool requestLinkEmbedded,
 50→                   ResolveCPUAndCPUFeaturesStatus &status) {
 51→  LLVMTarget target;
 52→  target.linkEmbedded = requestLinkEmbedded;
 53→  target.triple = (triple.empty() || triple == "host")
 54→                      ? llvm::sys::getProcessTriple()
 55→                      : triple;
 56→  llvm::Triple targetTriple(target.triple);
 57→  // Special casing if linkEmbedded.
 58→  if (targetTriple.isWasm()) {
 59→    // The embedded ELF loader is not supported on WebAssembly, so force it off.
 60→    target.linkEmbedded = false;
 61→  }
 62→  if (target.linkEmbedded) {
 63→    // Force the triple to something compatible with embedded linking.
 64→    targetTriple.setVendor(llvm::Triple::VendorType::UnknownVendor);
 65→    targetTriple.setEnvironment(llvm::Triple::EnvironmentType::EABI);
 66→    targetTriple.setOS(llvm::Triple::OSType::UnknownOS);
 67→    targetTriple.setObjectFormat(llvm::Triple::ObjectFormatType::ELF);
 68→  }
 69→  target.triple = targetTriple.str();
 70→  target.cpu = cpu;
 71→  target.cpuFeatures = cpuFeatures;
 72→  status = resolveCPUAndCPUFeatures(triple, target.cpu, target.cpuFeatures);
 73→  return target;
 74→}
 75→
 76→std::optional<LLVMTarget> LLVMTarget::createForHost() {
 77→  ResolveCPUAndCPUFeaturesStatus status;
 78→  auto triple = llvm::sys::getProcessTriple();
 79→  auto target = LLVMTarget::create(triple, /*cpu=*/"host",
 80→                                   /*cpuFeatures=*/"host",
 81→                                   /*requestLinkEmbedded=*/true, status);
 82→  if (status != ResolveCPUAndCPUFeaturesStatus::OK) {
 83→    llvm::errs() << "Internal error while creating host target: "
 84→                 << getMessage(status, triple) << "\n";
 85→    return std::nullopt;
 86→  }
 87→  if (target)
 88→    target->populateDefaultsFromTargetMachine();
 89→  return target;
 90→}
