 92→void LLVMTarget::print(llvm::raw_ostream &os) const {
 93→  os << "LLVMTarget{\n"
 94→     << "  triple=" << triple << ", cpu=" << cpu
 95→     << ", cpuFeatures=" << cpuFeatures << "\n"
 96→     << "  dataLayout=" << dataLayout << "\n"
 97→     << "  vectorWidthInBytes=" << vectorWidthInBytes << "\n"
 98→     << "  linkEmbedded=" << linkEmbedded << "\n"
 99→     << "  debugSymbols=" << debugSymbols << "\n"
100→     << "  sanitizer=" << static_cast<int>(sanitizerKind) << "\n"
101→     << "  staticLibraryOutput=" << staticLibraryOutput << "\n"
102→     << "  linkStatic=" << linkStatic << "\n"
103→     << "  pipelineTuningOptions={\n"
104→     << "    LoopInterleaving=" << pipelineTuningOptions.LoopInterleaving
105→     << "\n"
106→     << "    LoopVectorization=" << pipelineTuningOptions.LoopVectorization
107→     << "\n"
108→     << "    LoopUnrolling=" << pipelineTuningOptions.LoopUnrolling << "\n"
109→     << "    SLPVectorization=" << pipelineTuningOptions.SLPVectorization
110→     << "\n"
111→     << "  }, llvmTargetOptions={\n"
112→     << "    FloatABIType=" << static_cast<int>(llvmTargetOptions.FloatABIType)
113→     << "\n"
114→     << "  }\n"
115→     << "  ukernels=" << ukernels << "\n"
116→     << "  linkUkernelBitcode=" << linkUkernelBitcode << "\n"
117→     << "}\n";
118→}
