602→LLVMTargetOptions LLVMCPUTargetCLOptions::getTargetOptions() {
603→  LLVMTargetOptions targetOptions;
604→  targetOptions.systemLinkerPath = systemLinkerPath;
605→  targetOptions.embeddedLinkerPath = embeddedLinkerPath;
606→  targetOptions.wasmLinkerPath = wasmLinkerPath;
607→  targetOptions.keepLinkerArtifacts = keepLinkerArtifacts;
608→
609→  if (targetTriple.empty()) {
610→    targetTriple = llvm::sys::getProcessTriple();
611→  }
612→
613→  ResolveCPUAndCPUFeaturesStatus status;
614→  std::optional<LLVMTarget> maybeTarget = LLVMTarget::create(
615→      targetTriple, targetCPU, targetCPUFeatures, linkEmbedded, status);
616→  (void)status; // Ignore status here, since this code runs at target backend
617→                // registration time and we don't know if this backend will
618→                // actually be used, and these error statuses are non-fatal,
619→                // mostly warning about fallbacks. If the target backend is
620→                // actually used, any error here will also trigger in
621→                // loadFromConfigAttr, where we will generate an IR error.
622→  if (maybeTarget) {
623→    targetOptions.target = *maybeTarget;
624→  } else {
625→    llvm::errs() << "The target CPU is not properly defined.\n";
626→  }
627→  LLVMTarget &target = targetOptions.target;
628→  target.linkStatic = linkStatic;
629→  target.staticLibraryOutput = staticLibraryOutputPath;
630→  target.debugSymbols = debugSymbols;
631→  target.pipelineTuningOptions.LoopInterleaving = llvmLoopInterleaving;
632→  target.pipelineTuningOptions.LoopVectorization = llvmLoopVectorization;
633→  target.pipelineTuningOptions.LoopUnrolling = llvmLoopUnrolling;
634→  target.pipelineTuningOptions.SLPVectorization = llvmSLPVectorization;
635→  target.sanitizerKind = sanitizerKind;
636→  target.llvmTargetOptions.MCOptions.ABIName = targetABI;
637→  target.llvmTargetOptions.FloatABIType = targetFloatABI;
638→  target.dataLayout = targetDataLayout;
639→  target.vectorWidthInBytes = targetVectorWidthInBytes;
640→  target.ukernels = enableUkernels;
641→  target.linkUkernelBitcode = linkUKernelBitcode;
642→
643→  targetOptions.remarksFilter = remarksFilter;
644→
645→  target.populateDefaultsFromTargetMachine();
646→  return targetOptions;
647→}
