106→// Appends the |debugDatabase| to the end of |baseFile| and writes the footer
107→// so the runtime can find it.
108→static LogicalResult appendDebugDatabase(std::vector<int8_t> &baseFile,
109→                                         Artifact &debugFileArtifact) {
110→  auto debugFileOr = debugFileArtifact.read();
111→  if (!debugFileOr.has_value()) {
112→    return failure();
113→  }
114→  auto debugFile = std::move(debugFileOr).value();
115→
116→  // NOTE: we align the sizes so that the files all start at nice offsets.
117→  auto baseFileSize = IREE::Util::align(baseFile.size(), 16);
118→  auto debugFileSize = IREE::Util::align(debugFile.size(), 16);
119→
120→  // Matches iree_hal_system_executable_footer_t.
121→  struct Footer {
122→    uint8_t magic[8]; // IREEDBG\0
123→    uint32_t version;
124→    uint32_t flags;
125→    uint64_t libraryOffset;
126→    uint64_t librarySize;
127→    uint64_t debugOffset;
128→    uint64_t debugSize;
129→  } footer = {{0}};
130→  std::memcpy(footer.magic, "IREEDBG\0", sizeof(footer.magic));
131→  footer.version = 0;
132→  footer.librarySize = baseFile.size();
133→  footer.debugOffset = baseFileSize;
134→  footer.debugSize = debugFile.size();
135→
136→  baseFile.resize(baseFileSize + debugFileSize + sizeof(footer));
137→  std::memcpy(baseFile.data() + baseFileSize, debugFile.data(),
138→              debugFile.size());
139→  std::memcpy(baseFile.data() + baseFileSize + debugFileSize, &footer,
140→              sizeof(footer));
141→  return success();
142→}
