145→class RemarkDiagnosticHandler : public llvm::DiagnosticHandler {
146→public:
147→  RemarkDiagnosticHandler(StringRef filter) : filterRegex(filter) {}
148→
149→  bool handleDiagnostics(const llvm::DiagnosticInfo &DI) override {
150→    if (auto *remark = dyn_cast<llvm::DiagnosticInfoOptimizationBase>(&DI)) {
151→      if (filterRegex.match(remark->getPassName())) {
152→        std::string msg;
153→        llvm::raw_string_ostream os(msg);
154→        llvm::DiagnosticPrinterRawOStream printer(os);
155→        DI.print(printer);
156→        llvm::errs() << "[LLVM Remark] " << remark->getPassName() << ": "
157→                     << msg << "\n";
158→        return true;
159→      }
160→    }
161→    return false;
162→  }
163→
164→  // These three methods gate whether LLVM even *constructs* the remark.
165→  // Without returning true, the register allocator won't emit spill info.
166→  bool isPassedOptRemarkEnabled(StringRef passName) const override {
167→    return filterRegex.match(passName);
168→  }
169→  bool isMissedOptRemarkEnabled(StringRef passName) const override {
170→    return filterRegex.match(passName);
171→  }
172→  bool isAnalysisRemarkEnabled(StringRef passName) const override {
173→    return filterRegex.match(passName);
174→  }
175→
176→private:
177→  llvm::Regex filterRegex;
178→};
