181→class LLVMCPUTargetBackend final : public TargetBackend {
182→public:
183→  explicit LLVMCPUTargetBackend(LLVMTargetOptions options)
184→      : defaultOptions_(std::move(options)) {}
185→
186→  std::string getLegacyDefaultDeviceID() const override { return "llvm-cpu"; }
187→
188→  void getDefaultExecutableTargets(
189→      MLIRContext *context, StringRef deviceID, DictionaryAttr deviceConfigAttr,
190→      SmallVectorImpl<IREE::HAL::ExecutableTargetAttr> &executableTargetAttrs)
191→      const override {
192→    executableTargetAttrs.push_back(
193→        getExecutableTarget(context, defaultOptions_.target));
194→  }
195→
196→  void getHostExecutableTargets(MLIRContext *context, StringRef deviceID,
197→                                DictionaryAttr deviceConfigAttr,
198→                                SmallVectorImpl<IREE::HAL::ExecutableTargetAttr>
199→                                    &executableTargetAttrs) const override {
200→    std::optional<LLVMTarget> maybeTarget = LLVMTarget::createForHost();
201→    if (maybeTarget) {
202→      executableTargetAttrs.push_back(
203→          getExecutableTarget(context, *maybeTarget));
204→    }
205→  }
206→
207→  IREE::HAL::ExecutableTargetAttr
208→  getExecutableTarget(MLIRContext *context, const LLVMTarget &target) const {
209→    // Add some configurations to the `hal.executable.target` attribute.
210→    Builder b(context);
211→    SmallVector<NamedAttribute> configItems;
212→    target.storeToConfigAttrs(context, configItems);
213→
214→    // Compute the format used at runtime to select the executable loader.
215→    std::string format;
216→    if (target.linkStatic) {
217→      // Static libraries are just string references when serialized so we don't
218→      // need to specify the target architecture.
219→      format += "static";
220→    } else {
221→      // Construct the [loader]-[format]-[arch] triple.
222→      llvm::Triple targetTriple(target.getTriple());
223→      if (target.getLinkEmbedded()) {
224→        // Using the IREE embedded ELF format/loader.
225→        format += "embedded-elf-";
226→      } else {
227→        // System-specific shared library format.
228→        format += "system-";
229→        switch (targetTriple.getObjectFormat()) {
230→        case llvm::Triple::ObjectFormatType::COFF:
231→          format += "dll-";
232→          break;
233→        case llvm::Triple::ObjectFormatType::ELF:
234→          format += "elf-";
235→          break;
236→        case llvm::Triple::ObjectFormatType::MachO:
237→          format += "dylib-";
238→          break;
239→        case llvm::Triple::ObjectFormatType::Wasm:
240→          format += "wasm-";
241→          break;
242→        default:
243→          format += "unknown-";
244→          break;
245→        }
246→      }
247→      format += getIreeArchNameForTargetTriple(targetTriple);
248→    }
249→    return b.getAttr<IREE::HAL::ExecutableTargetAttr>(
250→        b.getStringAttr("llvm-cpu"), b.getStringAttr(format),
251→        b.getDictionaryAttr(configItems));
252→  }
253→
254→  void getDependentDialects(DialectRegistry &registry) const override {
255→    mlir::registerBuiltinDialectTranslation(registry);
256→    mlir::registerLLVMDialectTranslation(registry);
257→    mlir::registerArmSMEDialectTranslation(registry);
258→    mlir::registerArmSVEDialectTranslation(registry);
259→    // TODO: make inclusion of ArmNeon conditional?
260→    // clang-format off
261→    registry.insert<IREE::Codegen::IREECodegenDialect,
262→                    IREE::CPU::IREECPUDialect,
263→                    IREE::LinalgExt::IREELinalgExtDialect,
264→                    mlir::transform::TransformDialect,
265→                    pdl::PDLDialect,
266→                    pdl_interp::PDLInterpDialect,
267→                    arm_neon::ArmNeonDialect,
268→                    arm_sme::ArmSMEDialect,
269→                    arm_sve::ArmSVEDialect>();
270→    // clang-format on
271→  }
272→
273→  void
274→  buildConfigurationPassPipeline(IREE::HAL::ExecutableTargetAttr targetAttr,
275→                                 OpPassManager &passManager) override {
276→    buildLLVMCPUCodegenConfigurationPassPipeline(passManager);
277→  }
278→
279→  void buildTranslationPassPipeline(IREE::HAL::ExecutableTargetAttr targetAttr,
280→                                    OpPassManager &passManager) override {
281→    bool enableAArch64SME = isAArch64(targetAttr) && hasSMEFeature(targetAttr);
282→    buildLLVMCPUCodegenPassPipeline(passManager, enableAArch64SME);
283→  }
284→
285→  void buildLinkingPassPipeline(OpPassManager &passManager) override {
286→    buildLLVMCPULinkingPassPipeline(passManager, "llvm-cpu");
287→  }
288→
289→  // Gets the LLVM target from |variantOp|.
290→  // This will differ from the default options specified by command line flags
291→  // whenever multi-targeting.
292→  // Returns none and emits on failure.
293→  std::optional<LLVMTarget>
294→  getVariantTarget(IREE::HAL::ExecutableVariantOp variantOp) {
295→    auto configAttr = variantOp.getTarget().getConfiguration();
296→    return LLVMTarget::loadFromConfigAttr(variantOp.getLoc(), configAttr,
297→                                          defaultOptions_.target);
298→  }
299→
300→  LogicalResult serializeExecutable(const SerializationOptions &options,
301→                                    IREE::HAL::ExecutableVariantOp variantOp,
302→                                    OpBuilder &executableBuilder) override {
303→    // Perform the translation in a separate context to avoid any
304→    // multi-threading issues.
305→    llvm::LLVMContext context;
306→    if (!defaultOptions_.remarksFilter.empty()) {
307→      context.setDiagnosticHandler(
308→          std::make_unique<RemarkDiagnosticHandler>(
309→              defaultOptions_.remarksFilter));
310→    }
311→    auto maybeTarget = getVariantTarget(variantOp);
312→    if (!maybeTarget)
313→      return failure();
314→    const LLVMTarget &target = *maybeTarget;
315→    LLVM_DEBUG(dbgs() << "LLVM-CPU SerializeExecutable:\n"
316→                      << "-----------------------------\n";
317→               target.print(dbgs()));
318→
319→    // For debugging effective options in live builds, uncomment the following.
320→    // dbgs() << "LLVM-CPU ";
321→    // target.print(dbgs());
322→
323→    // We name our files after the executable name so that they are easy to
324→    // track both during compilation (logs/artifacts/etc), as outputs (final
325→    // intermediate code/binary files), and at runtime (loaded
326→    // libraries/symbols/etc).
327→    auto libraryName =
328→        variantOp->getParentOfType<IREE::HAL::ExecutableOp>().getName().str();
329→
330→    // Validate flags for output mode.
331→    if (target.getLinkEmbedded() && target.linkStatic) {
332→      return variantOp.emitError()
333→             << "cannot embed ELF and produce static library simultaneously";
334→    }
335→
336→    // Try to create the LLVM target machine interface for the variant target.
337→    auto targetMachine = createTargetMachine(target);
338→    if (!targetMachine) {
339→      return mlir::emitError(variantOp.getLoc())
340→             << "failed to create target machine for target triple '"
341→             << target.getTriple() << "'";
342→    }
343→
344→    // Specialize the module to the target triple.
345→    // The executable will have been cloned into other ExecutableVariantOps for
346→    // other triples so it's fine to mutate in-place.
347→    const llvm::Triple &targetTriple = targetMachine->getTargetTriple();
348→    variantOp.getInnerModule()->setAttr(
349→        LLVM::LLVMDialect::getTargetTripleAttrName(),
350→        executableBuilder.getStringAttr(targetTriple.str()));
351→
352→    // At this moment we are leaving MLIR LLVM dialect land translating module
353→    // into target independent LLVMIR.
354→    auto llvmModule = mlir::translateModuleToLLVMIR(variantOp.getInnerModule(),
355→                                                    context, libraryName);
356→    if (!llvmModule) {
357→      return variantOp.emitError() << "failed to translate the MLIR LLVM "
358→                                      "dialect to the native llvm::Module";
359→    }
360→
361→    // Configure the functions in the module. This may override defaults set
362→    // during the MLIR->LLVM conversion.
363→    for (auto &func : *llvmModule) {
364→      // Enable frame pointers to ensure that stack unwinding works, e.g. in
365→      // Tracy. In principle this could also be achieved by enabling unwind
366→      // tables, but we tried that and that didn't work in Tracy (which uses
367→      // libbacktrace), while enabling frame pointers worked.
368→      // https://github.com/iree-org/iree/issues/3957
369→      func.addFnAttr("frame-pointer", "all");
370→
371→      // -ffreestanding-like behavior.
372→      func.addFnAttr("no-builtins");
373→
374→      // Our dispatches are all hot - that's kind of the point.
375→      // This may favor more aggressive optimizations.
376→      func.addFnAttr("hot");
377→    }
378→
379→    // Build the IREE HAL executable library metadata. The runtime uses this to
380→    // find the entry point functions and their information.
381→    LibraryBuilder::Mode libraryBuilderMode =
382→        target.debugSymbols ? LibraryBuilder::Mode::INCLUDE_REFLECTION_ATTRS
383→                            : LibraryBuilder::Mode::NONE;
384→    LibraryBuilder libraryBuilder(llvmModule.get(), libraryBuilderMode,
385→                                  LibraryBuilder::Version::LATEST);
386→
387→    switch (target.sanitizerKind) {
388→    case SanitizerKind::kNone: {
389→      libraryBuilder.setSanitizerKind(LibraryBuilder::SanitizerKind::NONE);
390→      break;
391→    }
392→    case SanitizerKind::kAddress: {
393→      libraryBuilder.setSanitizerKind(LibraryBuilder::SanitizerKind::ADDRESS);
394→      for (auto &function : llvmModule->getFunctionList()) {
395→        function.addFnAttr(llvm::Attribute::SanitizeAddress);
396→      }
397→    } break;
398→    case SanitizerKind::kThread: {
399→      libraryBuilder.setSanitizerKind(LibraryBuilder::SanitizerKind::THREAD);
400→      for (auto &function : llvmModule->getFunctionList()) {
401→        function.addFnAttr(llvm::Attribute::SanitizeThread);
402→      }
403→    } break;
404→    }
405→
406→    // Declare dynamically imported functions.
407→    auto importsAttrName =
408→        StringAttr::get(variantOp.getContext(), "hal.executable.imports");
409→    if (auto importsAttr =
410→            variantOp->getAttrOfType<ArrayAttr>(importsAttrName)) {
411→      for (auto importAttr : importsAttr.getAsValueRange<ArrayAttr>()) {
412→        auto nameAttr = llvm::cast<StringAttr>(importAttr[0]);
413→        auto weakAttr = llvm::cast<BoolAttr>(importAttr[1]);
414→        libraryBuilder.addImport(nameAttr.getValue(), weakAttr.getValue());
415→      }
416→      variantOp->removeAttr(importsAttrName);
417→    }
418→
419→    // Declare exported entry points.
420→    auto align16 = llvm::Attribute::getWithAlignment(context, llvm::Align(16));
421→    for (auto exportOp : variantOp.getBlock().getOps<ExecutableExportOp>()) {
422→      // Find the matching function in the LLVM module.
423→      auto *llvmFunc = llvmModule->getFunction(exportOp.getName());
424→      if (!llvmFunc)
425→        continue;
426→      llvmFunc->setLinkage(llvm::GlobalValue::LinkageTypes::InternalLinkage);
427→      llvmFunc->setDSOLocal(true);
428→
429→      // Tag the function parameters in case they got removed during conversion.
430→      // (%arg0: environment, %arg1: dispatch_state, %arg2: workgroup_state)
431→      for (unsigned i = 0; i <= 2; ++i) {
432→        llvmFunc->addParamAttr(i, llvm::Attribute::NonNull);
433→        llvmFunc->addParamAttr(i, llvm::Attribute::NoAlias);
434→        llvmFunc->addParamAttr(i, align16);
435→      }
436→
437→      LibraryBuilder::DispatchAttrs dispatchAttrs = {0};
438→
439→      // Entry points may optionally specify that they require workgroup local
440→      // memory. We fetch that value here and plumb it through so the runtime
441→      // knows how much memory to reserve and pass in.
442→      dispatchAttrs.localMemorySize = exportOp.getWorkgroupLocalMemory()
443→                                          .value_or(APInt(64, 0))
444→                                          .getSExtValue();
445→
446→      // Specify the constant and binding information used to validate
447→      // dispatches.
448→      if (auto layoutAttr = exportOp.getLayout()) {
449→        dispatchAttrs.constantCount = layoutAttr.getConstants();
450→        dispatchAttrs.bindingCount = layoutAttr.getBindings().size();
451→      }
452→
453→      LibraryBuilder::SourceLocation sourceLocation;
454→      if (options.debugLevel >= 1) {
455→        if (auto loc = findFirstFileLoc(exportOp.getLoc())) {
456→          sourceLocation = {"", loc->getFilename().str(), loc->getLine()};
457→        }
458→      }
459→      SmallVector<LibraryBuilder::SourceLocation> stageLocations;
460→      if (options.debugLevel >= 3) {
461→        if (auto locsAttr = exportOp.getSourceLocsAttr()) {
462→          for (auto locAttr : locsAttr.getValue()) {
463→            if (auto loc =
464→                    findFirstFileLoc(cast<LocationAttr>(locAttr.getValue()))) {
465→              stageLocations.push_back({
466→                  locAttr.getName().str(),
467→                  loc->getFilename().str(),
468→                  loc->getLine(),
469→              });
470→            }
471→          }
472→        }
473→      }
474→      libraryBuilder.addExport(exportOp.getName(), std::move(sourceLocation),
475→                               std::move(stageLocations), /*tag=*/"",
476→                               dispatchAttrs, llvmFunc);
477→    }
478→
479→    // Embed source files (if present).
480→    if (auto sourcesAttr = variantOp.getSourcesAttr()) {
481→      for (auto sourceAttr : sourcesAttr.getValue()) {
482→        if (auto resourceAttr = dyn_cast_if_present<DenseResourceElementsAttr>(
483→                sourceAttr.getValue())) {
484→          auto handle = resourceAttr.getRawHandle();
485→          SmallVector<char> rawData;
486→          llvm::append_range(rawData, handle.getBlob()->getData());
487→          libraryBuilder.addSourceFile(sourceAttr.getName(),
488→                                       std::move(rawData));
489→        }
490→      }
491→    }
492→
493→    auto queryFunctionName = std::string(kQueryFunctionName);
494→    if (target.linkStatic) {
495→      // Static library query functions must be unique to support multiple
496→      // libraries in the same namespace.
497→      queryFunctionName = libraryName + "_library_query";
498→    }
499→    auto *queryLibraryFunc = libraryBuilder.build(queryFunctionName);
500→
501→    // The query function must be exported for dynamic libraries.
502→    queryLibraryFunc->setDSOLocal(false);
503→    queryLibraryFunc->setVisibility(
504→        llvm::GlobalValue::VisibilityTypes::DefaultVisibility);
505→    queryLibraryFunc->setLinkage(
506→        llvm::GlobalValue::LinkageTypes::ExternalLinkage);
507→    queryLibraryFunc->setDLLStorageClass(
508→        llvm::GlobalValue::DLLStorageClassTypes::DLLExportStorageClass);
509→
510→    // If linking dynamically, find a suitable linker tool and configure the
511→    // module with any options that tool requires.
512→    std::unique_ptr<LinkerTool> linkerTool;
513→    if (!target.linkStatic) {
514→      // Grab a linker tool based on the options (and target environment).
515→      // This uses the defaultOptions_ in order to get paths and such, which
516→      // are environmental, but replace the target with the actual one.
517→      LLVMTargetOptions options = defaultOptions_;
518→      options.target = target;
519→      linkerTool = LinkerTool::getForTarget(targetTriple, options);
520→      if (!linkerTool) {
521→        return mlir::emitError(variantOp.getLoc())
522→               << "failed to find a target linker for the given target triple '"
523→               << targetTriple.str() << "'";
524→      }
525→
526→      // Configure the module with any code generation options required later by
527→      // linking (such as initializer functions).
528→      if (failed(linkerTool->configureModule(llvmModule.get(),
529→                                             {queryLibraryFunc}))) {
530→        return variantOp.emitError()
531→               << "failed to configure LLVM module for target linker";
532→      }
533→    }
534→
535→    // Specialize the module to our target machine.
536→    llvmModule->setDataLayout(targetMachine->createDataLayout());
537→    llvmModule->setTargetTriple(targetMachine->getTargetTriple().str());
538→
539→    // Dump just the codegen bitcode before linking and optimization.
540→    if (!options.dumpIntermediatesPath.empty()) {
541→      dumpLLVMModuleToPath(options.dumpIntermediatesPath, options.dumpBaseName,
542→                           variantOp.getName(), ".codegen", *llvmModule);
543→    }
544→
545→    // Statically link libraries into our module prior to LLVM optimizations.
546→    // This approximates LTO.
547→    llvm::Linker moduleLinker(*llvmModule);
548→
549→    // Link any bitcode files specified on the command line.
550→    if (failed(linkCmdlineBitcodeFiles(variantOp.getLoc(), moduleLinker,
551→                                       llvm::Linker::OverrideFromSrc,
552→                                       *targetMachine, context))) {
553→      return failure();
554→    }
555→
556→    // Link any bitcode objects specified in executable.object attributes and
557→    // specialize them for the current config.
558→    if (failed(linkBitcodeObjects(variantOp.getLoc(), moduleLinker,
559→                                  llvm::Linker::LinkOnlyNeeded, *targetMachine,
560→                                  variantOp.getObjectsAttr(), context))) {
561→      return failure();
562→    }
563→
564→    // Link our libdevice after all codegen and user objects as they may
565→    // reference it. Some of the functions in here are only known used after
566→    // we perform LLVM ISel and need to be pulled in whether they are used or
567→    // not.
568→    if (failed(linkBitcodeModule(
569→            variantOp.getLoc(), moduleLinker, llvm::Linker::OverrideFromSrc,
570→            *targetMachine, "libdevice",
571→            loadDeviceBitcode(targetMachine.get(), context),
572→            [&](llvm::Module &module) {
573→              specializeDeviceModule(variantOp, module, *targetMachine);
574→            }))) {
575→      return mlir::emitError(variantOp.getLoc())
576→             << "failed linking in builtin library for target triple '"
577→             << targetTriple.str() << "'";
578→    }
579→
580→    if (target.getLinkEmbedded()) {
581→      // Link musl last and pull in all of it - this is sad but LLVM will take
582→      // IR intrinsics and generate calls out to libc during code generation and
583→      // we have no control over that - if we don't provide the symbols here
584→      // then linking with ld will fail.
585→      if (failed(linkBitcodeModule(
586→              variantOp.getLoc(), moduleLinker, llvm::Linker::OverrideFromSrc,
587→              *targetMachine, "libmusl",
588→              loadMuslBitcode(targetMachine.get(), context)))) {
589→        return mlir::emitError(variantOp.getLoc())
590→               << "failed linking in builtin library for target triple '"
591→               << targetTriple.str() << "'";
592→      }
593→    }
594→
595→    if (target.linkUkernelBitcode) {
596→      // Link in ukernel bitcode.
597→      if (hasUkernel(variantOp.getTarget())) {
598→        llvm::Expected<std::unique_ptr<llvm::Module>> bitcode =
599→            loadUKernelBitcode(targetMachine.get(), context);
600→        if (!bitcode) {
601→          return mlir::emitError(variantOp.getLoc())
602→                 << "failed to load ukernel bitcode: "
603→                 << llvm::toString(bitcode.takeError());
604→        }
605→
606→        if (bitcode.get()) {
607→          StringRef bitcodeName = bitcode.get()->getName();
608→          if (failed(linkBitcodeModule(variantOp.getLoc(), moduleLinker,
609→                                       llvm::Linker::LinkOnlyNeeded,
610→                                       *targetMachine, bitcodeName,
611→                                       std::move(bitcode), {}))) {
612→            return mlir::emitError(variantOp.getLoc())
613→                   << "failed linking in architecture-specific ukernel bitcode "
614→                      "for target triple '"
615→                   << targetTriple.str() << "'";
616→          }
617→        }
618→      }
619→    }
620→
621→    // Strip any compiler identifiers that may have snuck in. We let the linker
622→    // tag the module.
623→    auto *llvmIdent = llvmModule->getNamedMetadata("llvm.ident");
624→    if (llvmIdent)
625→      llvmIdent->clearOperands();
626→
627→    // Dump all linked bitcode prior to optimization.
628→    if (!options.dumpIntermediatesPath.empty()) {
629→      dumpLLVMModuleToPath(options.dumpIntermediatesPath, options.dumpBaseName,
630→                           variantOp.getName(), ".linked", *llvmModule);
631→    }
632→
633→    // LLVM opt passes that perform code generation optimizations/transformation
634→    // similar to what a frontend would do.
635→    if (failed(
636→            runLLVMIRPasses(target, targetMachine.get(), llvmModule.get()))) {
637→      return variantOp.emitError()
638→             << "failed to run LLVM-IR opt passes for IREE::HAL::ExecutableOp "
639→                "targeting '"
640→             << targetTriple.str() << "'";
641→    }
642→
643→    // Fixup visibility from any symbols we may link in - we want to hide all
644→    // but the query entry point.
645→    // Note: can't move this before runLLVMIRPasses at the moment, as further
646→    // symbol references may still be created past this point, namely to math
647→    // functions, e.g. `llvm.frem` lowering to a call to `fmodf`.
648→    SetVector<llvm::Function *> preservedFuncs;
649→    preservedFuncs.insert(queryLibraryFunc);
650→    fixupVisibility(*llvmModule, preservedFuncs);
651→
652→    // Dump bitcode post-linking and optimization.
653→    if (!options.dumpIntermediatesPath.empty()) {
654→      dumpLLVMModuleToPath(options.dumpIntermediatesPath, options.dumpBaseName,
655→                           variantOp.getName(), ".optimized", *llvmModule);
656→    }
657→
658→    SmallVector<Artifact> objectFiles;
659→
660→    // Emit the base object file containing the bulk of our code.
661→    // This must come first such that we have the proper library linking order.
662→    {
663→      // NOTE: today we just use a single object file, however if we wanted to
664→      // scale code generation and linking we'd want to generate one per
665→      // function (or something like that). A single object file is also
666→      // instrumental to static library generation (which only supports one
667→      // object file per library).
668→      std::string objectData;
669→      if (failed(runEmitObjFilePasses(targetMachine.get(), llvmModule.get(),
670→                                      llvm::CodeGenFileType::ObjectFile,
671→                                      &objectData))) {
672→        return variantOp.emitError()
673→               << "failed to compile LLVM-IR module to an object file";
674→      }
675→      if (!options.dumpIntermediatesPath.empty()) {
676→        dumpDataToPath(options.dumpIntermediatesPath, options.dumpBaseName,
677→                       variantOp.getName(), ".o", objectData);
678→      }
679→      auto objectFile = Artifact::createTemporary(libraryName, "o");
680→      auto &os = objectFile.outputFile->os();
681→      os << objectData;
682→      os.flush();
683→      os.close();
684→      objectFiles.push_back(std::move(objectFile));
685→    }
686→
687→    // Dump assembly listing after optimization, which is just a textual
688→    // representation of the object file we generate below.
689→    if (!options.dumpIntermediatesPath.empty()) {
690→      std::string asmData;
691→      if (failed(runEmitObjFilePasses(targetMachine.get(), llvmModule.get(),
692→                                      llvm::CodeGenFileType::AssemblyFile,
693→                                      &asmData))) {
694→        return variantOp.emitError()
695→               << "failed to compile LLVM-IR module to an assembly file";
696→      }
697→      dumpDataToPath(options.dumpIntermediatesPath, options.dumpBaseName,
698→                     variantOp.getName(), ".s", asmData);
699→    }
700→
701→    // If custom object files were specified then add those to our artifact set.
702→    // These will either be combined into the resulting static library or linked
703→    // statically into the resulting dynamic library.
704→    SmallVector<IREE::HAL::ExecutableObjectAttr> linkerObjectAttrs;
705→    IREE::HAL::ExecutableObjectAttr::filterObjects(variantOp.getObjectsAttr(),
706→                                                   {".o", ".obj", ".a", ".lib"},
707→                                                   linkerObjectAttrs);
708→    for (auto [index, attr] : llvm::enumerate(linkerObjectAttrs)) {
709→      auto objectAttr = llvm::cast<IREE::HAL::ExecutableObjectAttr>(attr);
710→      if (auto dataAttr = objectAttr.getData()) {
711→        objectFiles.push_back(Artifact::createTemporary(
712→            objectFiles.front().path + "_object_" + std::to_string(index),
713→            llvm::sys::path::extension(objectAttr.getPath())));
714→      } else {
715→        auto absolutePath = objectAttr.getAbsolutePath();
716→        if (failed(absolutePath)) {
717→          llvm::errs()
718→              << "ERROR: referenced object file not found on any path; use "
719→                 "--iree-hal-executable-object-search-path= to add search "
720→                 "paths: "
721→              << objectAttr << "\n";
722→          return failure();
723→        }
724→        objectFiles.push_back(Artifact::fromFile(*absolutePath));
725→      }
726→    }
727→
728→    if (target.linkStatic) {
729→      return serializeStaticLibraryExecutable(options, target, variantOp,
730→                                              executableBuilder, libraryName,
731→                                              queryFunctionName, objectFiles);
732→    } else {
733→      return serializeDynamicLibraryExecutable(
734→          options, target, variantOp, executableBuilder, libraryName,
735→          targetTriple, objectFiles, linkerTool.get());
736→    }
737→  }
738→
739→  LogicalResult serializeStaticLibraryExecutable(
740→      const SerializationOptions &options, const LLVMTarget &target,
741→      IREE::HAL::ExecutableVariantOp variantOp, OpBuilder &executableBuilder,
742→      const std::string &libraryName, const std::string &queryFunctionName,
743→      const SmallVector<Artifact> &objectFiles) {
744→    if (objectFiles.size() != 1) {
745→      // Static library output only supports single object libraries.
746→      return variantOp.emitError() << "generating static libraries from "
747→                                      "multiple object files is not supported";
748→    }
749→
750→    // Copy the static object file to the specified output along with
751→    // generated header file.
752→    if (!outputStaticLibrary(libraryName, queryFunctionName,
753→                             target.staticLibraryOutput, objectFiles[0].path)) {
754→      return variantOp.emitError() << "static library generation failed";
755→    }
756→
757→    // Embed the library name in the executable binary op. This informs the
758→    // loader which static library to load for the target binary.
759→    std::vector<uint8_t> libraryNameVector(libraryName.begin(),
760→                                           libraryName.end());
761→    executableBuilder.create<IREE::HAL::ExecutableBinaryOp>(
762→        variantOp.getLoc(), variantOp.getSymName(), "static",
763→        libraryNameVector);
764→
765→    return success();
766→  }
767→
768→  LogicalResult serializeDynamicLibraryExecutable(
769→      const SerializationOptions &options, const LLVMTarget &target,
770→      IREE::HAL::ExecutableVariantOp variantOp, OpBuilder &executableBuilder,
771→      const std::string &libraryName, const llvm::Triple &targetTriple,
772→      const SmallVector<Artifact> &objectFiles, LinkerTool *linkerTool) {
773→    // Link the generated object files into a dylib.
774→    auto linkArtifactsOr =
775→        linkerTool->linkDynamicLibrary(libraryName, objectFiles);
776→    if (!linkArtifactsOr.has_value()) {
777→      return mlir::emitError(variantOp.getLoc())
778→             << "failed to link executable and generate target dylib (check "
779→                "above for more specific error messages)";
780→    }
781→    auto &linkArtifacts = linkArtifactsOr.value();
782→    if (defaultOptions_.keepLinkerArtifacts) {
783→      mlir::emitRemark(variantOp.getLoc())
784→          << "linker artifacts for " << variantOp.getName() << " preserved:\n"
785→          << "    " << linkArtifacts.libraryFile.path;
786→      linkArtifacts.keepAllFiles();
787→      for (auto &objectFile : objectFiles) {
788→        objectFile.keep();
789→      }
790→    }
791→
792→    if (target.getLinkEmbedded()) {
793→      // Load the linked ELF file and pack into an attr.
794→      auto elfFile = linkArtifacts.libraryFile.read();
795→      if (!elfFile.has_value()) {
796→        return variantOp.emitError()
797→               << "failed to read back dylib temp file at "
798→               << linkArtifacts.libraryFile.path;
799→      }
800→      if (!options.dumpBinariesPath.empty()) {
801→        dumpDataToPath<int8_t>(options.dumpBinariesPath, options.dumpBaseName,
802→                               variantOp.getName(), ".so", *elfFile);
803→      }
804→      auto bufferAttr = DenseIntElementsAttr::get(
805→          VectorType::get({static_cast<int64_t>(elfFile->size())},
806→                          IntegerType::get(executableBuilder.getContext(), 8)),
807→          std::move(elfFile.value()));
808→
809→      // Add the binary to the parent hal.executable.
810→      auto binaryOp = executableBuilder.create<IREE::HAL::ExecutableBinaryOp>(
811→          variantOp.getLoc(), variantOp.getSymName(),
812→          variantOp.getTarget().getFormat(), bufferAttr);
813→      binaryOp.setMimeTypeAttr(
814→          executableBuilder.getStringAttr("application/x-elf"));
815→    } else {
816→      const char *mimeType = nullptr;
817→      const char *extension = "";
818→      switch (targetTriple.getObjectFormat()) {
819→      case llvm::Triple::ObjectFormatType::COFF:
820→        mimeType = "application/x-msdownload";
821→        extension = ".dll";
822→        break;
823→      case llvm::Triple::ObjectFormatType::ELF:
824→        mimeType = "application/x-elf";
825→        extension = ".so";
826→        break;
827→      case llvm::Triple::ObjectFormatType::MachO:
828→        mimeType = "application/x-dylib";
829→        extension = ".dylib";
830→        break;
831→      case llvm::Triple::ObjectFormatType::Wasm:
832→        mimeType = "application/wasm";
833→        extension = ".wasm";
834→        break;
835→      default:
836→        mimeType = "application/octet-stream";
837→        break;
838→      }
839→
840→      // Load the linked system library and optionally tag on the debug
841→      // database. This debug database sits at the tail of the file and is
842→      // ignored by system loaders and tools but still accessible to the runtime
843→      // loader. Not all platforms have separate debug databases and need this.
844→      auto libraryFileOr = linkArtifacts.libraryFile.read();
845→      if (!libraryFileOr.has_value()) {
846→        return variantOp.emitError()
847→               << "failed to read back dylib temp file at "
848→               << linkArtifacts.libraryFile.path;
849→      }
850→      auto libraryFile = std::move(libraryFileOr).value();
851→      if (target.debugSymbols && linkArtifacts.debugFile.outputFile) {
852→        if (failed(appendDebugDatabase(libraryFile, linkArtifacts.debugFile))) {
853→          return variantOp.emitError()
854→                 << "failed to append debug database to dylib file";
855→        }
856→      }
857→      if (!options.dumpBinariesPath.empty()) {
858→        dumpDataToPath<int8_t>(options.dumpBinariesPath, options.dumpBaseName,
859→                               variantOp.getName(), extension, libraryFile);
860→      }
861→      auto bufferAttr = DenseIntElementsAttr::get(
862→          VectorType::get({static_cast<int64_t>(libraryFile.size())},
863→                          IntegerType::get(executableBuilder.getContext(), 8)),
864→          std::move(libraryFile));
865→
866→      // Add the binary to the parent hal.executable.
867→      auto binaryOp = executableBuilder.create<IREE::HAL::ExecutableBinaryOp>(
868→          variantOp.getLoc(), variantOp.getSymName(),
869→          variantOp.getTarget().getFormat(), bufferAttr);
870→      binaryOp.setMimeTypeAttr(executableBuilder.getStringAttr(mimeType));
871→    }
872→
873→    return success();
874→  }
875→
876→private:
877→  // Default options as registered from the command line. Should not be
878→  // relied on outside of getDefaultDeviceTarget() since it represents
879→  // a static "cross compiling" config and would override more specific
880→  // settings.
881→  const LLVMTargetOptions defaultOptions_;
