103→// Appends the |debugDatabase| to the end of |baseFile| and writes the footer
104→// so the runtime can find it.
105→static LogicalResult appendDebugDatabase(std::vector<int8_t> &baseFile,
106→                                         Artifact &debugFileArtifact) {
107→  auto debugFileOr = debugFileArtifact.read();
108→  if (!debugFileOr.has_value()) {
109→    return failure();
110→  }
111→  auto debugFile = std::move(debugFileOr).value();
112→
113→  // NOTE: we align the sizes so that the files all start at nice offsets.
114→  auto baseFileSize = IREE::Util::align(baseFile.size(), 16);
115→  auto debugFileSize = IREE::Util::align(debugFile.size(), 16);
116→
117→  // Matches iree_hal_system_executable_footer_t.
118→  struct Footer {
119→    uint8_t magic[8]; // IREEDBG\0
120→    uint32_t version;
121→    uint32_t flags;
122→    uint64_t libraryOffset;
123→    uint64_t librarySize;
124→    uint64_t debugOffset;
125→    uint64_t debugSize;
126→  } footer = {{0}};
127→  std::memcpy(footer.magic, "IREEDBG\0", sizeof(footer.magic));
128→  footer.version = 0;
129→  footer.librarySize = baseFile.size();
130→  footer.debugOffset = baseFileSize;
131→  footer.debugSize = debugFile.size();
132→
133→  baseFile.resize(baseFileSize + debugFileSize + sizeof(footer));
134→  std::memcpy(baseFile.data() + baseFileSize, debugFile.data(),
135→              debugFile.size());
136→  std::memcpy(baseFile.data() + baseFileSize + debugFileSize, &footer,
137→              sizeof(footer));
138→  return success();
139→}
