148→  void getDefaultExecutableTargets(
149→      MLIRContext *context, StringRef deviceID, DictionaryAttr deviceConfigAttr,
150→      SmallVectorImpl<IREE::HAL::ExecutableTargetAttr> &executableTargetAttrs)
151→      const override {
152→    executableTargetAttrs.push_back(
153→        getExecutableTarget(context, defaultOptions_.target));
154→  }
155→
156→  void getHostExecutableTargets(MLIRContext *context, StringRef deviceID,
157→                                DictionaryAttr deviceConfigAttr,
158→                                SmallVectorImpl<IREE::HAL::ExecutableTargetAttr>
159→                                    &executableTargetAttrs) const override {
160→    std::optional<LLVMTarget> maybeTarget = LLVMTarget::createForHost();
161→    if (maybeTarget) {
162→      executableTargetAttrs.push_back(
163→          getExecutableTarget(context, *maybeTarget));
164→    }
