196→std::optional<LLVMTarget>
197→LLVMTarget::loadFromConfigAttr(Location loc, DictionaryAttr config,
198→                               const LLVMTarget &defaultTarget) {
199→  bool hasFailures = false;
200→  auto getString = [&](StringRef name, StringRef fallback,
201→                       bool required) -> StringRef {
202→    Attribute attr = config.get(name);
203→    if (auto sattr = llvm::dyn_cast_if_present<StringAttr>(attr)) {
204→      return sattr.strref();
205→    } else {
206→      if (required) {
207→        hasFailures = true;
208→        emitError(loc) << "executable config '" << name
209→                       << "' required but not present on attribute";
210→      }
211→      return fallback;
212→    }
213→  };
214→  auto getOptionalString = [&](StringRef name) -> std::optional<StringRef> {
215→    Attribute attr = config.get(name);
216→    if (auto sattr = llvm::dyn_cast_if_present<StringAttr>(attr)) {
217→      return sattr.strref();
218→    } else if (attr) {
219→      hasFailures = true;
220→      emitError(loc) << "executable config '" << name
221→                     << "' requires string but got " << attr;
222→    }
223→    return {};
224→  };
225→  auto getBool = [&](StringRef name, bool fallback) -> bool {
226→    Attribute attr = config.get(name);
227→    if (auto battr = llvm::dyn_cast_if_present<BoolAttr>(attr)) {
228→      return battr.getValue();
229→    } else if (attr) {
230→      hasFailures = true;
231→      emitError(loc) << "executable config '" << name
232→                     << "' requires bool but got " << attr;
233→    }
234→    return fallback;
235→  };
236→  auto getInt64 = [&](StringRef name, int64_t fallback) -> int64_t {
237→    Attribute attr = config.get(name);
238→    if (auto iattr = llvm::dyn_cast_if_present<IntegerAttr>(attr)) {
239→      return iattr.getValue().getSExtValue();
240→    } else if (attr) {
241→      hasFailures = true;
242→      emitError(loc) << "executable config '" << name
243→                     << "' requires i64 but got " << attr;
244→    }
245→    return fallback;
246→  };
247→
248→  LLVMTarget target;
249→
250→  // Constructor arguments.
251→  auto triple = getOptionalString("target_triple");
252→  auto cpu = getOptionalString("cpu");
253→  auto cpuFeatures = getOptionalString("cpu_features");
254→  bool linkEmbedded = getBool("link_embedded", DEFAULT_LINK_EMBEDDED);
255→  if (triple || cpu || cpuFeatures) {
256→    if (!triple) {
257→      emitError(loc) << "executable config 'cpu' or 'cpu_features' must be "
258→                        "accompanied by 'target_triple'";
259→      return {};
260→    }
261→    ResolveCPUAndCPUFeaturesStatus status;
262→    std::optional<LLVMTarget> maybeTarget =
263→        LLVMTarget::create(*triple, cpu.value_or(""), cpuFeatures.value_or(""),
264→                           linkEmbedded, status);
265→    if (status != ResolveCPUAndCPUFeaturesStatus::OK) {
266→      // TODO(#18561): after people have had time to adapt, typically by adding
267→      // --iree-llvmcpu-target-cpu=generic (or another value) to their invokes,
268→      // promote this warning to an error by changing emitWarning to emitError
269→      // and nulling maybeTarget.
270→      emitWarning(loc) << "while creating CPU target: "
271→                       << getMessage(status, *triple);
272→    }
273→    if (!maybeTarget) {
274→      return {};
275→    }
276→    target.copy(*maybeTarget);
277→  } else {
278→    target.copy(defaultTarget);
279→  }
280→
281→  target.dataLayout = getString("data_layout", DEFAULT_DATA_LAYOUT, false);
282→  target.vectorWidthInBytes =
283→      getInt64("native_vector_size", DEFAULT_VECTOR_WIDTH_IN_BYTES);
284→
285→  target.debugSymbols = getBool("debug_symbols", DEFAULT_DEBUG_SYMBOLS);
286→  target.linkStatic = getBool("link_static", DEFAULT_LINK_STATIC);
287→  auto sanitizer = getOptionalString("sanitizer");
288→  if (sanitizer) {
289→    if (sanitizer == "none")
290→      target.sanitizerKind = SanitizerKind::kNone;
291→    else if (sanitizer == "address")
292→      target.sanitizerKind = SanitizerKind::kAddress;
293→    else if (sanitizer == "thread")
294→      target.sanitizerKind = SanitizerKind::kThread;
295→    else {
296→      emitError(loc) << "executable config unexpected value for 'sanitizer': "
297→                     << *sanitizer;
298→      return {};
299→    }
300→  }
301→  target.staticLibraryOutput = getString("static_library_output", "", false);
302→
303→  target.pipelineTuningOptions.LoopInterleaving = getBool(
304→      "loop_interleaving", target.pipelineTuningOptions.LoopInterleaving);
305→  target.pipelineTuningOptions.LoopVectorization = getBool(
306→      "loop_vectorization", target.pipelineTuningOptions.LoopVectorization);
307→  target.pipelineTuningOptions.LoopUnrolling =
308→      getBool("loop_unrolling", target.pipelineTuningOptions.LoopUnrolling);
309→  target.pipelineTuningOptions.SLPVectorization = getBool(
310→      "slp_vectorization", target.pipelineTuningOptions.SLPVectorization);
311→  auto targetAbi = getOptionalString("target_abi");
312→  if (targetAbi)
313→    target.llvmTargetOptions.MCOptions.ABIName = *targetAbi;
314→  auto floatAbi = getOptionalString("float_abi");
315→  if (floatAbi) {
316→    if (floatAbi == "default")
317→      target.llvmTargetOptions.FloatABIType = llvm::FloatABI::Default;
318→    else if (floatAbi == "soft")
319→      target.llvmTargetOptions.FloatABIType = llvm::FloatABI::Default;
320→    else if (floatAbi == "hard")
321→      target.llvmTargetOptions.FloatABIType = llvm::FloatABI::Default;
322→    else {
323→      emitError(loc) << "executable config unexpected value for 'float_abi'";
324→      return {};
325→    }
326→  }
327→
328→  target.ukernels = getString("ukernels", target.ukernels, false);
329→  target.linkUkernelBitcode =
330→      getBool("link_ukernel_bitcode", target.linkUkernelBitcode);
331→
332→  if (hasFailures) {
333→    return {};
334→  }
335→  target.populateDefaultsFromTargetMachine();
336→  return target;
