260→  LogicalResult serializeExecutable(const SerializationOptions &options,
261→                                    IREE::HAL::ExecutableVariantOp variantOp,
262→                                    OpBuilder &executableBuilder) override {
263→    // Perform the translation in a separate context to avoid any
264→    // multi-threading issues.
265→    llvm::LLVMContext context;
266→    auto maybeTarget = getVariantTarget(variantOp);
267→    if (!maybeTarget)
268→      return failure();
269→    const LLVMTarget &target = *maybeTarget;
270→    LLVM_DEBUG(dbgs() << "LLVM-CPU SerializeExecutable:\n"
271→                      << "-----------------------------\n";
272→               target.print(dbgs()));
273→
274→    // For debugging effective options in live builds, uncomment the following.
275→    // dbgs() << "LLVM-CPU ";
276→    // target.print(dbgs());
277→
278→    // We name our files after the executable name so that they are easy to
279→    // track both during compilation (logs/artifacts/etc), as outputs (final
280→    // intermediate code/binary files), and at runtime (loaded
281→    // libraries/symbols/etc).
282→    auto libraryName =
283→        variantOp->getParentOfType<IREE::HAL::ExecutableOp>().getName().str();
284→
285→    // Validate flags for output mode.
286→    if (target.getLinkEmbedded() && target.linkStatic) {
287→      return variantOp.emitError()
288→             << "cannot embed ELF and produce static library simultaneously";
289→    }
290→
291→    // Try to create the LLVM target machine interface for the variant target.
292→    auto targetMachine = createTargetMachine(target);
293→    if (!targetMachine) {
294→      return mlir::emitError(variantOp.getLoc())
295→             << "failed to create target machine for target triple '"
296→             << target.getTriple() << "'";
297→    }
298→
299→    // Specialize the module to the target triple.
300→    // The executable will have been cloned into other ExecutableVariantOps for
301→    // other triples so it's fine to mutate in-place.
302→    const llvm::Triple &targetTriple = targetMachine->getTargetTriple();
303→    variantOp.getInnerModule()->setAttr(
304→        LLVM::LLVMDialect::getTargetTripleAttrName(),
305→        executableBuilder.getStringAttr(targetTriple.str()));
306→
307→    // At this moment we are leaving MLIR LLVM dialect land translating module
308→    // into target independent LLVMIR.
309→    auto llvmModule = mlir::translateModuleToLLVMIR(variantOp.getInnerModule(),
310→                                                    context, libraryName);
311→    if (!llvmModule) {
312→      return variantOp.emitError() << "failed to translate the MLIR LLVM "
313→                                      "dialect to the native llvm::Module";
314→    }
315→
316→    // Configure the functions in the module. This may override defaults set
317→    // during the MLIR->LLVM conversion.
318→    for (auto &func : *llvmModule) {
319→      // Enable frame pointers to ensure that stack unwinding works, e.g. in
320→      // Tracy. In principle this could also be achieved by enabling unwind
321→      // tables, but we tried that and that didn't work in Tracy (which uses
322→      // libbacktrace), while enabling frame pointers worked.
323→      // https://github.com/iree-org/iree/issues/3957
324→      func.addFnAttr("frame-pointer", "all");
325→
326→      // -ffreestanding-like behavior.
327→      func.addFnAttr("no-builtins");
328→
329→      // Our dispatches are all hot - that's kind of the point.
330→      // This may favor more aggressive optimizations.
331→      func.addFnAttr("hot");
332→    }
333→
334→    // Build the IREE HAL executable library metadata. The runtime uses this to
335→    // find the entry point functions and their information.
336→    LibraryBuilder::Mode libraryBuilderMode =
337→        target.debugSymbols ? LibraryBuilder::Mode::INCLUDE_REFLECTION_ATTRS
338→                            : LibraryBuilder::Mode::NONE;
339→    LibraryBuilder libraryBuilder(llvmModule.get(), libraryBuilderMode,
340→                                  LibraryBuilder::Version::LATEST);
341→
342→    switch (target.sanitizerKind) {
343→    case SanitizerKind::kNone: {
344→      libraryBuilder.setSanitizerKind(LibraryBuilder::SanitizerKind::NONE);
345→      break;
346→    }
347→    case SanitizerKind::kAddress: {
348→      libraryBuilder.setSanitizerKind(LibraryBuilder::SanitizerKind::ADDRESS);
349→      for (auto &function : llvmModule->getFunctionList()) {
350→        function.addFnAttr(llvm::Attribute::SanitizeAddress);
351→      }
352→    } break;
353→    case SanitizerKind::kThread: {
354→      libraryBuilder.setSanitizerKind(LibraryBuilder::SanitizerKind::THREAD);
355→      for (auto &function : llvmModule->getFunctionList()) {
356→        function.addFnAttr(llvm::Attribute::SanitizeThread);
357→      }
358→    } break;
359→    }

