   namespace {
   class RemarkDiagnosticHandler : public llvm::DiagnosticHandler {
   public:
     RemarkDiagnosticHandler(StringRef filter) : filterRegex(filter) {}

     bool handleDiagnostics(const llvm::DiagnosticInfo &DI) override {
       if (auto *remark = dyn_cast<llvm::DiagnosticInfoOptimizationBase>(&DI)) {
         if (filterRegex.match(remark->getPassName())) {
           std::string msg;
           llvm::raw_string_ostream os(msg);
           llvm::DiagnosticPrinterRawOStream printer(os);
           DI.print(printer);
           llvm::errs() << "[LLVM Remark] " << remark->getPassName() << ": "
                        << msg << "\n";
           return true;
         }
       }
       return false;
     }

     // These three methods gate whether LLVM even *constructs* the remark.
     // Without returning true, the register allocator won't emit spill info.
     bool isPassedOptRemarkEnabled(StringRef passName) const override {
       return filterRegex.match(passName);
     }
     bool isMissedOptRemarkEnabled(StringRef passName) const override {
       return filterRegex.match(passName);
     }
     bool isAnalysisRemarkEnabled(StringRef passName) const override {
       return filterRegex.match(passName);
     }

   private:
     llvm::Regex filterRegex;
   };
   } // namespace
   ```

